record.field:
{
    "type": "object",
    "properties": {
        "snippet_key": {
            "type": "string",
            "description": "The template key of the building block (e.g., 'website.s_cover', 'website.s_text_image')"
        }
    },
    "required": ["snippet_key"]
}

{
    "type": "object",
    "properties": {
        "html": {
            "type": "string",
            "description": "HTML content for append/prepend/replace/replace_all actions. Not needed for edit_content or remove."
        },
        "action": {
            "type": "string",
            "enum": ["edit_content", "append", "replace", "remove", "prepend", "replace_all"],
            "description": "'edit_content' edits elements within a section (PREFERRED), 'append' adds at end, 'prepend' adds at beginning, 'replace' replaces entire section, 'remove' deletes section, 'replace_all' replaces all page content."
        },
        "section_index": {
            "type": "integer",
            "description": "1-based index of the section to target (from the page structure in initial context)."
        },
        "content_replacements": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "selector": {"type": "string", "description": "CSS selector for the element within the section (e.g. 'h1', '.lead', '.btn-primary')"},
                    "new_inner_html": {"type": "string", "description": "New innerHTML. Can include formatting tags (strong, em, a, br, span)."}
                },
                "required": ["selector", "new_inner_html"]
            },
            "description": "Replace innerHTML of targeted elements. Preserves the element and surrounding DOM."
        },
        "class_operations": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "selector": {"type": "string", "description": "CSS selector for the element. Leave empty or omit to target the section element itself."},
                    "add": {"type": "string", "description": "Space-separated CSS classes to add (e.g. 'o_cc o_cc3 pt48')"},
                    "remove": {"type": "string", "description": "Space-separated CSS classes to remove (e.g. 'o_cc1 pt32')"}
                },
                "required": []
            },
            "description": "Add or remove CSS classes on elements. Use this for background color presets (o_cc o_cc1-o_cc5), spacing (pt/pb), text alignment, etc. When selector is empty, targets the section element itself."
        }
    },
    "required": ["action"]
}

{
    "type": "object",
    "properties": {
        "css_content": {
            "type": "string",
            "description": "The SCSS rules to append to user_custom_rules.scss"
        }
    },
    "required": ["css_content"]
}
